def get_thesis_by_discipline(discipline: str) -> dict:
    """按学科获取论题样本

    Args:
        discipline: 学科标识，如 computer_science、literature 等。

    Returns:
        包含该学科标题、摘要、大纲、报告的字典。
    """
    titles = SAMPLE_THESIS_TITLES.get(discipline, [])
    abstracts = [a for a in SAMPLE_THESIS_ABSTRACTS if a["discipline"] == discipline]
    outlines = [o for o in SAMPLE_THESIS_OUTLINES if o["discipline"] == discipline]
    reports = [r for r in SAMPLE_FULL_REPORTS if r["discipline"] == discipline]
    return {
        "discipline": discipline,
        "titles": titles,
        "abstracts": abstracts,
        "outlines": outlines,
        "reports": reports,
    }


